import tensorflow as tf
from tensorflow import keras
from tensorflow.keras import layers
import pandas as pd
import numpy as np
import os
import io
from flask import Flask, request, jsonify
from werkzeug.utils import secure_filename
import hashlib
from datetime import datetime

app = Flask(__name__)

UPLOAD_FOLDER = 'uploads'
MODEL_FOLDER = 'models'
ALLOWED_EXTENSIONS = {'csv', 'png', 'jpg', 'jpeg'}

os.makedirs(UPLOAD_FOLDER, exist_ok=True)
os.makedirs(MODEL_FOLDER, exist_ok=True)

app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER
app.config['MAX_CONTENT_LENGTH'] = 16 * 1024 * 1024

class ModelTrainer:
    def __init__(self):
        self.model = None
        self.training_data = []
        self.labels = []
        
    def create_model(self, input_shape, num_classes):
        self.model = keras.Sequential([
            layers.Input(shape=input_shape),
            layers.Conv2D(32, (3, 3), activation='relu'),
            layers.MaxPooling2D((2, 2)),
            layers.Conv2D(64, (3, 3), activation='relu'),
            layers.MaxPooling2D((2, 2)),
            layers.Conv2D(64, (3, 3), activation='relu'),
            layers.Flatten(),
            layers.Dense(64, activation='relu'),
            layers.Dropout(0.5),
            layers.Dense(num_classes, activation='softmax')
        ])
        
        self.model.compile(
            optimizer='adam',
            loss='sparse_categorical_crossentropy',
            metrics=['accuracy']
        )
        
    def load_csv_data(self, filepath):
        df = pd.read_csv(filepath)
        return df
    
    def preprocess_image(self, image_path, target_size=(128, 128)):
        img = tf.io.read_file(image_path)
        img = tf.image.decode_image(img, channels=3)
        img = tf.image.resize(img, target_size)
        img = img / 255.0
        return img
    
    def add_training_example(self, data, label):
        self.training_data.append(data)
        self.labels.append(label)
    
    def train(self, epochs=10, batch_size=32):
        if len(self.training_data) == 0:
            return None
            
        X = np.array(self.training_data)
        y = np.array(self.labels)
        
        if self.model is None:
            num_classes = len(np.unique(y))
            input_shape = X.shape[1:]
            self.create_model(input_shape, num_classes)
        
        history = self.model.fit(
            X, y,
            epochs=epochs,
            batch_size=batch_size,
            validation_split=0.2,
            verbose=1
        )
        
        return history
    
    def save_model(self, model_path):
        if self.model:
            self.model.save(model_path)
    
    def load_model(self, model_path):
        if os.path.exists(model_path):
            self.model = keras.models.load_model(model_path)

trainer = ModelTrainer()

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

@app.route('/upload_csv', methods=['POST'])
def upload_csv():
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    file = request.files['file']
    
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
        unique_filename = f"{timestamp}_{filename}"
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], unique_filename)
        file.save(filepath)
        
        try:
            df = trainer.load_csv_data(filepath)
            
            if 'image_path' in df.columns and 'label' in df.columns:
                for _, row in df.iterrows():
                    img_path = row['image_path']
                    label = row['label']
                    
                    if os.path.exists(img_path):
                        img = trainer.preprocess_image(img_path)
                        trainer.add_training_example(img.numpy(), label)
                
                return jsonify({
                    'message': 'CSV data loaded successfully',
                    'samples_added': len(df),
                    'total_samples': len(trainer.training_data)
                }), 200
            else:
                features = df.iloc[:, :-1].values
                labels = df.iloc[:, -1].values
                
                for feature, label in zip(features, labels):
                    trainer.add_training_example(feature, label)
                
                return jsonify({
                    'message': 'CSV data loaded successfully',
                    'samples_added': len(df),
                    'total_samples': len(trainer.training_data)
                }), 200
                
        except Exception as e:
            return jsonify({'error': f'Error processing CSV: {str(e)}'}), 500
    
    return jsonify({'error': 'Invalid file type'}), 400

@app.route('/upload_image', methods=['POST'])
def upload_image():
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    if 'label' not in request.form:
        return jsonify({'error': 'No label provided'}), 400
    
    file = request.files['file']
    label = int(request.form['label'])
    
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
        unique_filename = f"{timestamp}_{filename}"
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], unique_filename)
        file.save(filepath)
        
        try:
            img = trainer.preprocess_image(filepath)
            trainer.add_training_example(img.numpy(), label)
            
            return jsonify({
                'message': 'Image uploaded and added to training set',
                'filename': unique_filename,
                'label': label,
                'total_samples': len(trainer.training_data)
            }), 200
            
        except Exception as e:
            return jsonify({'error': f'Error processing image: {str(e)}'}), 500
    
    return jsonify({'error': 'Invalid file type'}), 400

@app.route('/contribute_batch', methods=['POST'])
def contribute_batch():
    if 'files[]' not in request.files:
        return jsonify({'error': 'No files provided'}), 400
    
    if 'labels[]' not in request.form:
        return jsonify({'error': 'No labels provided'}), 400
    
    files = request.files.getlist('files[]')
    labels = request.form.getlist('labels[]')
    
    if len(files) != len(labels):
        return jsonify({'error': 'Number of files and labels must match'}), 400
    
    added_count = 0
    errors = []
    
    for file, label in zip(files, labels):
        if file and allowed_file(file.filename):
            try:
                filename = secure_filename(file.filename)
                timestamp = datetime.now().strftime('%Y%m%d_%H%M%S')
                unique_filename = f"{timestamp}_{filename}"
                filepath = os.path.join(app.config['UPLOAD_FOLDER'], unique_filename)
                file.save(filepath)
                
                img = trainer.preprocess_image(filepath)
                trainer.add_training_example(img.numpy(), int(label))
                added_count += 1
                
            except Exception as e:
                errors.append(f"{file.filename}: {str(e)}")
    
    return jsonify({
        'message': 'Batch contribution processed',
        'samples_added': added_count,
        'total_samples': len(trainer.training_data),
        'errors': errors
    }), 200

@app.route('/train', methods=['POST'])
def train_model():
    data = request.get_json() or {}
    epochs = data.get('epochs', 10)
    batch_size = data.get('batch_size', 32)
    
    if len(trainer.training_data) == 0:
        return jsonify({'error': 'No training data available'}), 400
    
    try:
        history = trainer.train(epochs=epochs, batch_size=batch_size)
        
        model_path = os.path.join(MODEL_FOLDER, 'community_model.h5')
        trainer.save_model(model_path)
        
        return jsonify({
            'message': 'Model trained successfully',
            'final_accuracy': float(history.history['accuracy'][-1]),
            'final_loss': float(history.history['loss'][-1]),
            'epochs': epochs,
            'model_path': model_path
        }), 200
        
    except Exception as e:
        return jsonify({'error': f'Training error: {str(e)}'}), 500

@app.route('/predict', methods=['POST'])
def predict():
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400
    
    file = request.files['file']
    
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400
    
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        filepath = os.path.join(app.config['UPLOAD_FOLDER'], f"temp_{filename}")
        file.save(filepath)
        
        try:
            if trainer.model is None:
                model_path = os.path.join(MODEL_FOLDER, 'community_model.h5')
                if os.path.exists(model_path):
                    trainer.load_model(model_path)
                else:
                    return jsonify({'error': 'No trained model available'}), 400
            
            img = trainer.preprocess_image(filepath)
            img = tf.expand_dims(img, 0)
            
            predictions = trainer.model.predict(img)
            predicted_class = int(np.argmax(predictions[0]))
            confidence = float(predictions[0][predicted_class])
            
            os.remove(filepath)
            
            return jsonify({
                'predicted_class': predicted_class,
                'confidence': confidence,
                'all_probabilities': predictions[0].tolist()
            }), 200
            
        except Exception as e:
            if os.path.exists(filepath):
                os.remove(filepath)
            return jsonify({'error': f'Prediction error: {str(e)}'}), 500
    
    return jsonify({'error': 'Invalid file type'}), 400

@app.route('/model_stats', methods=['GET'])
def model_stats():
    stats = {
        'total_training_samples': len(trainer.training_data),
        'model_exists': trainer.model is not None,
        'unique_labels': len(np.unique(trainer.labels)) if trainer.labels else 0
    }
    
    if trainer.model:
        stats['model_summary'] = []
        for layer in trainer.model.layers:
            stats['model_summary'].append({
                'name': layer.name,
                'type': layer.__class__.__name__,
                'output_shape': str(layer.output_shape)
            })
    
    return jsonify(stats), 200

@app.route('/reset', methods=['POST'])
def reset_training():
    trainer.training_data = []
    trainer.labels = []
    trainer.model = None
    
    return jsonify({'message': 'Training data and model reset'}), 200

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)